frame_eqs:
warp=0;
spd=0.9; sm=0.5;

dc=pow(0.99,30/fps);
cv=max(max(bass,mid),treb);
cvs=cvs*dc+cv*(1-dc);
b=above(cv,cvs+pk)*above(time,tb+0.2);
tb=time*b+tb*(1-b);
pk=pk*0.9*(1-b)+b*cvs;
q7=b;

q1=rt1; q2=rt2; q3=rt3; q4=rt4; q5=rt5;
q6=ht;
q8=fc1; q9=fc2;
q10=bt;

bt=bt*spd+bts*(1-spd);

bts=max(0,bts-0.1);

bts=b;

rt1=rt1+rts1;
rt2=rt2+rts2;
rt3=rt3+rts3;
rt4=rt4+rts4;
rt5=rt5+rts5;

ht=ht+hts;

rts1=rts1*sm+rtsc1*(1-sm);
rts2=rts2*sm+rtsc2*(1-sm);
rts3=rts3*sm+rtsc3*(1-sm);
rts4=rts4*sm+rtsc4*(1-sm);
rts5=rts5*sm+rtsc5*(1-sm);

hts=hts*sm+htsc*(1-sm);

rtsc1=if(b,(rand(200)-100)/2000,rtsc1);
rtsc2=if(b,(rand(200)-100)/2000,rtsc2);
rtsc3=if(b,(rand(200)-100)/2000,rtsc3);
rtsc4=if(b,(rand(200)-100)/2000,rtsc4);
rtsc5=if(b,(rand(200)-100)/2000,rtsc5);

htsc=if(b,(rand(200)-100)/1000,htsc);

fc1=if(b,floor(rand(3))+1,fc1);
fc2=if(b,floor(rand(3))+1,fc2);

wave_0_per_point:
pi=acos(-1);

i=sample;
x=(sin(i*pi*2+q1)+cos(i*pi*4+q2)+sin(i*pi*8+q3)+cos(i*pi*16+q4)+sin(i*pi*32+q5))/6;
y=(cos(i*pi*2+q1)+sin(i*pi*4+q2)+cos(i*pi*8+q3)+sin(i*pi*16+q4)+cos(i*pi*32+q5))/6;

ox=x; oy=y;

x=x*0.5+0.5;
y=y*0.5+0.5;

r=abs(sqrt(ox*ox+oy*oy+ox*oy));
g=abs(sqrt(ox*ox-oy*oy+ox/3));
b=abs(sqrt(oy*oy-ox*ox+oy/3));

// YUV-based gray scale
bw=r*0.299+g*0.587+b*0.114;

r=r*t1+bw*(1-t1);
g=g*t2+bw*(1-t2);
b=b*t3+bw*(1-t3);
